#include <stdio.h>
#include <stdlib.h>
#include <time.h>

void print_random_sequence(unsigned int seed, int count) {
    srand(seed);  // Seed the generator
    printf("Seed %u: ", seed);
    for (int i = 0; i < count; i++) {
        printf("%d ", rand());
    }
    printf("\n");
}

int main() {
    // Same seed produces same sequence
    print_random_sequence(42, 5);
    print_random_sequence(42, 5);  // Identical output

    // Different seed produces different sequence
    print_random_sequence(100, 5);

    // Time-based seed for randomness
    srand(time(NULL));
    printf("Random: %d\n", rand());

    return 0;
}
